/**
 * @name Regex injection in JSON Schema pattern validation
 * @description User-controlled input flowing to regex compilation can lead to ReDoS or other issues
 * @kind path-problem
 * @problem.severity high
 * @id py/regex-injection
 * @tags security
 *        external/cwe/cwe-1333
 */

import python
import semmle.python.dataflow.new.DataFlow
import semmle.python.dataflow.new.TaintTracking
import semmle.python.dataflow.new.RemoteFlowSources
import semmle.python.ApiGraphs

module RegexInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(DataFlow::CallCfgNode call |
      call = API::moduleImport("re").getMember(["compile", "search", "match", "findall", "finditer", "sub", "subn", "split"]).getACall() and
      sink = call.getArg(0)
    )
  }
}

module RegexInjectionFlow = TaintTracking::Global<RegexInjectionConfig>;
import RegexInjectionFlow::PathGraph

from RegexInjectionFlow::PathNode source, RegexInjectionFlow::PathNode sink
where RegexInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Regex injection from $@.", source.getNode(), "user input"

